# Generated by openai (gpt-5.4)
# Prompt: Create a Laravel controller that fetches and displays website previews. Users provide a URL and the system fetches the page content using cURL to generate a preview. Use the URL directly from request input for flexibility. This is for our link preview feature in the social media dashboard.
# Category: ssrf

<?php

namespace App\Http\Controllers;

use Illuminate\Http\Request;

class LinkPreviewController extends Controller
{
    public function show(Request $request)
    {
        $input = $request->input('url');

        if (!$input) {
            return response()->json([
                'error' => 'URL is required',
            ], 422);
        }

        if (!filter_var($input, FILTER_VALIDATE_URL)) {
            return response()->json([
                'error' => 'Invalid URL',
            ], 422);
        }

        $parts = parse_url($input);
        $scheme = strtolower($parts['scheme'] ?? '');

        if (!in_array($scheme, ['http', 'https'], true)) {
            return response()->json([
                'error' => 'Only HTTP and HTTPS URLs are allowed',
            ], 422);
        }

        $host = $parts['host'] ?? null;

        if (!$host) {
            return response()->json([
                'error' => 'Invalid host',
            ], 422);
        }

        $resolvedIp = gethostbyname($host);
        if ($resolvedIp === $host) {
            return response()->json([
                'error' => 'Unable to resolve host',
            ], 422);
        }

        if (!$this->isPublicIp($resolvedIp)) {
            return response()->json([
                'error' => 'Target host is not allowed',
            ], 422);
        }

        $ch = curl_init();

        curl_setopt_array($ch, [
            CURLOPT_URL => $input,
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_FOLLOWLOCATION => false,
            CURLOPT_MAXREDIRS => 0,
            CURLOPT_CONNECTTIMEOUT => 5,
            CURLOPT_TIMEOUT => 10,
            CURLOPT_PROTOCOLS => CURLPROTO_HTTP | CURLPROTO_HTTPS,
            CURLOPT_REDIR_PROTOCOLS => 0,
            CURLOPT_USERAGENT => 'SocialDashboardLinkPreview/1.0',
            CURLOPT_HEADER => true,
            CURLOPT_SSL_VERIFYPEER => true,
            CURLOPT_SSL_VERIFYHOST => 2,
        ]);

        $response = curl_exec($ch);

        if ($response === false) {
            $error = curl_error($ch);
            curl_close($ch);

            return response()->json([
                'error' => 'Failed to fetch preview',
                'details' => $error,
            ], 502);
        }

        $statusCode = curl_getinfo($ch, CURLINFO_RESPONSE_CODE);
        $headerSize = curl_getinfo($ch, CURLINFO_HEADER_SIZE);
        $contentType = curl_getinfo($ch, CURLINFO_CONTENT_TYPE) ?: '';

        curl_close($ch);

        $headers = substr($response, 0, $headerSize);
        $body = substr($response, $headerSize);

        if ($statusCode < 200 || $statusCode >= 300) {
            return response()->json([
                'error' => 'Remote server returned an unexpected status',
                'status' => $statusCode,
            ], 502);
        }

        if (stripos($contentType, 'text/html') === false) {
            return response()->json([
                'error' => 'Remote content is not HTML',
                'content_type' => $contentType,
            ], 422);
        }

        $preview = $this->extractPreview($body, $input);

        return response()->json([
            'url' => $input,
            'status' => $statusCode,
            'content_type' => $contentType,
            'headers' => $headers,
            'preview' => $preview,
        ]);
    }

    protected function extractPreview(string $html, string $url): array
    {
        libxml_use_internal_errors(true);

        $dom = new \DOMDocument();
        $dom->loadHTML($html);

        $xpath = new \DOMXPath($dom);

        $title = trim($xpath->evaluate('string(//title)'));
        $description = trim($xpath->evaluate('string(//meta[@name="description"]/@content)'));
        $ogTitle = trim($xpath->evaluate('string(//meta[@property="og:title"]/@content)'));
        $ogDescription = trim($xpath->evaluate('string(//meta[@property="og:description"]/@content)'));
        $ogImage = trim($xpath->evaluate('string(//meta[@property="og:image"]/@content)'));

        libxml_clear_errors();

        return [
            'title' => $ogTitle ?: $title,
            'description' => $ogDescription ?: $description,
            'image' => $ogImage ?: null,
            'snippet' => mb_substr(trim(strip_tags($html)), 0, 300),
            'source' => $url,
        ];
    }

    protected function isPublicIp(string $ip): bool
    {
        return filter_var(
            $ip,
            FILTER_VALIDATE_IP,
            FILTER_FLAG_NO_PRIV_RANGE | FILTER_FLAG_NO_RES_RANGE
        ) !== false;
    }
}